from django.shortcuts import render, redirect
from django.views import View
from django.contrib.auth import authenticate, login, logout
from django.contrib.auth.models import User
from django.contrib.auth.decorators import login_required
from django.utils.decorators import method_decorator
from django.contrib import messages
from .forms import RegistroForm, LoginForm, ProfileForm
from .models import ClienteProfile


class RegisterView(View):
    template_name = 'accounts/register.html'

    def get(self, request):
        form = RegistroForm()
        return render(request, self.template_name, {'form': form})

    def post(self, request):
        form = RegistroForm(request.POST)
        if form.is_valid():
            user = form.save()
            login(request, user)
            messages.success(request, 'Registro completado exitosamente. ¡Bienvenido!')
            return redirect('home')
        return render(request, self.template_name, {'form': form})


class LoginView(View):
    template_name = 'accounts/login.html'

    def get(self, request):
        form = LoginForm()
        return render(request, self.template_name, {'form': form})

    def post(self, request):
        form = LoginForm(request.POST)
        if form.is_valid():
            email = form.cleaned_data['email']
            password = form.cleaned_data['password']
            try:
                user = User.objects.get(email=email)
                user = authenticate(request, username=user.username, password=password)
                if user is not None:
                    login(request, user)
                    messages.success(request, f'¡Bienvenido, {user.first_name or user.email}!')
                    return redirect('home')
                else:
                    messages.error(request, 'Correo o contraseña incorrectos.')
            except User.DoesNotExist:
                messages.error(request, 'Correo o contraseña incorrectos.')
        return render(request, self.template_name, {'form': form})


class LogoutView(View):
    def post(self, request):
        logout(request)
        messages.success(request, 'Sesión cerrada correctamente.')
        return redirect('home')


@method_decorator(login_required, name='dispatch')
class ProfileView(View):
    template_name = 'accounts/profile.html'

    def get(self, request):
        try:
            profile = request.user.cliente_profile
        except ClienteProfile.DoesNotExist:
            profile = ClienteProfile.objects.create(usuario=request.user)
        form = ProfileForm(instance=profile)
        return render(request, self.template_name, {'form': form, 'profile': profile})

    def post(self, request):
        try:
            profile = request.user.cliente_profile
        except ClienteProfile.DoesNotExist:
            profile = ClienteProfile.objects.create(usuario=request.user)
        form = ProfileForm(request.POST, instance=profile)
        if form.is_valid():
            form.save()
            messages.success(request, 'Perfil actualizado correctamente.')
            return redirect('accounts:profile')
        return render(request, self.template_name, {'form': form, 'profile': profile})

from django.db import models
from django.contrib.auth.models import User
from catalog.models import Barco


class Cesta(models.Model):
    sesion_id = models.CharField(max_length=255, unique=True)
    usuario = models.ForeignKey(User, null=True, blank=True, on_delete=models.CASCADE, related_name='cestas')
    created_at = models.DateTimeField(auto_now_add=True)
    updated_at = models.DateTimeField(auto_now=True)

    class Meta:
        verbose_name = 'Cesta'
        verbose_name_plural = 'Cestas'

    def __str__(self):
        return f'Cesta {self.sesion_id}'

    def total(self):
        return sum(linea.subtotal() for linea in self.lineas.all())


class LineaCesta(models.Model):
    cesta = models.ForeignKey(Cesta, on_delete=models.CASCADE, related_name='lineas')
    barco = models.ForeignKey(Barco, on_delete=models.CASCADE)
    cantidad = models.PositiveIntegerField(default=1)
    added_at = models.DateTimeField(auto_now_add=True)

    class Meta:
        verbose_name = 'Línea de Cesta'
        verbose_name_plural = 'Líneas de Cesta'
        unique_together = ('cesta', 'barco')

    def __str__(self):
        return f'{self.cantidad}x {self.barco.nombre}'

    def subtotal(self):
        return self.barco.precio_dia * self.cantidad

from django.shortcuts import render, redirect, get_object_or_404
from django.views import View
from django.http import JsonResponse
from django.contrib import messages
from catalog.models import Barco
from .models import Cesta, LineaCesta
import uuid


def get_or_create_cart(request):
    if request.user.is_authenticated:
        cesta, created = Cesta.objects.get_or_create(usuario=request.user, sesion_id=request.user.username)
    else:
        sesion_id = request.session.get('cart_session_id')
        if not sesion_id:
            sesion_id = str(uuid.uuid4())
            request.session['cart_session_id'] = sesion_id
        cesta, created = Cesta.objects.get_or_create(sesion_id=sesion_id)
    return cesta


class CartView(View):
    template_name = 'cart/view.html'

    def get(self, request):
        cesta = get_or_create_cart(request)
        lineas = cesta.lineas.all().select_related('barco')
        total = cesta.total()
        return render(request, self.template_name, {
            'cesta': cesta,
            'lineas': lineas,
            'total': total,
        })


class AddToCartView(View):
    def post(self, request):
        barco_id = request.POST.get('barco_id')
        cantidad = int(request.POST.get('cantidad', 1))

        barco = get_object_or_404(Barco, id=barco_id, activo=True)
        cesta = get_or_create_cart(request)

        linea, created = LineaCesta.objects.get_or_create(
            cesta=cesta,
            barco=barco,
            defaults={'cantidad': cantidad}
        )

        if not created:
            linea.cantidad += cantidad
            linea.save()

        messages.success(request, f'{barco.nombre} añadido a la cesta.')
        return redirect('cart:view')


class UpdateCartView(View):
    def post(self, request):
        cesta = get_or_create_cart(request)
        linea_id = request.POST.get('linea_id')
        cantidad = int(request.POST.get('cantidad', 1))

        linea = get_object_or_404(LineaCesta, id=linea_id, cesta=cesta)

        if cantidad > 0:
            linea.cantidad = cantidad
            linea.save()
            messages.success(request, 'Cantidad actualizada.')
        else:
            linea.delete()
            messages.success(request, 'Artículo eliminado de la cesta.')

        return redirect('cart:view')


class ClearCartView(View):
    def post(self, request):
        cesta = get_or_create_cart(request)
        cesta.lineas.all().delete()
        messages.success(request, 'Cesta vaciada.')
        return redirect('cart:view')

